72	export function Rules({
73	  showAddRuleButton = true,
74	}: {
75	  showAddRuleButton?: boolean;
76	}) {
77	  const { data, isLoading, error, mutate } = useRules();
78	  const { setOpen } = useSidebar();
79	  const { setInput } = useChat();
80	
81	  const { userLabels } = useLabels();
82	  const ruleDialog = useDialogState<{
83	    ruleId?: string;
84	    editMode?: boolean;
85	    duplicateRule?: RulesResponse[number];
86	  }>();
87	  const onCreateRule = () => ruleDialog.onOpen();
88	
89	  const { emailAccountId, provider } = useAccount();
90	  const { executeAsync: toggleRule } = useAction(
91	    toggleRuleAction.bind(null, emailAccountId),
92	  );
93	
94	  const rules: RulesResponse = useMemo(() => {
95	    const existingRules = data || [];
96	
97	    const systemRulePlaceholders = SYSTEM_RULE_ORDER.map((systemType) => {
98	      const existingRule = existingRules.find(
99	        (r) => r.systemType === systemType,
100	      );
101	      if (existingRule) return existingRule;
102	
103	      const ruleConfiguration = getRuleConfig(systemType);
104	
105	      return {
106	        id: `placeholder-${systemType}`,
107	        name: ruleConfiguration.name,
108	        instructions: ruleConfiguration.instructions,
109	        enabled: false,
110	        runOnThreads: false,
111	        automate: true,
112	        actions: getDefaultActions(systemType, provider).map((action) => ({
113	          ...action,
114	          emailAccountId,
115	          messagingChannelEmailAccountId: null,
116	        })),
117	        group: null,
118	        emailAccountId: emailAccountId,
119	        createdAt: new Date(),
120	        updatedAt: new Date(),
121	        categoryFilterType: null,
122	        conditionalOperator: LogicalOperator.OR,
123	        groupId: null,
124	        systemType,
125	        to: null,
126	        from: null,
127	        subject: null,
128	        body: null,
129	        promptText: null,
130	      };
131	    });
132	
133	    const userRules = existingRules.filter((rule) => !rule.systemType);
134	
135	    return sortRulesForAutomation([...systemRulePlaceholders, ...userRules]);
136	  }, [data, emailAccountId, provider]);
137	
138	  const hasRules = !!rules?.length;
139	
140	  return (
141	    <div className="space-y-6">
142	      <Card>
143	        <LoadingContent loading={isLoading} error={error}>
144	          {hasRules ? (
145	            <Table>
146	              <TableHeader>
147	                <TableRow>
148	                  <TableHead className="w-16 px-2 sm:px-4">Enabled</TableHead>
149	                  <TableHead className="px-2 sm:px-4">Name</TableHead>
150	                  <TableHead className="hidden sm:table-cell px-2 sm:px-4">
151	                    Prompt
152	                  </TableHead>
153	                  <TableHead className="px-2 sm:px-4">Action</TableHead>
154	                  <TableHead className="w-fit whitespace-nowrap px-1">
155	                    {showAddRuleButton && (
156	                      <div className="flex justify-end">
157	                        <div className="my-2">
158	                          <Button size="sm" onClick={onCreateRule}>
159	                            <PlusIcon className="mr-2 hidden size-4 md:block" />
160	                            Add Rule
161	                          </Button>
162	                        </div>
163	                      </div>
164	                    )}
165	                  </TableHead>
166	                </TableRow>
167	              </TableHeader>
168	              <TableBody>
169	                {rules.map((rule) => {
170	                  const isPlaceholder = rule.id.startsWith("placeholder-");
171	
172	                  return (
173	                    <TableRow
174	                      key={rule.id}
175	                      className={`${!rule.enabled ? "bg-muted opacity-60" : ""} ${
176	                        isPlaceholder ? "cursor-default" : "cursor-pointer"
177	                      }`}
178	                      onClick={() => {
179	                        if (isPlaceholder) return;
180	                        ruleDialog.onOpen({
181	                          ruleId: rule.id,
182	                          editMode: false,
183	                        });
184	                      }}
185	                    >
186	                      <TableCell
187	                        onClick={(e) => e.stopPropagation()}
188	                        className="text-center p-2 sm:p-4"
189	                      >
190	                        <Switch
191	                          size="sm"
192	                          checked={rule.enabled}
193	                          disabled={
194	                            !!rule.systemType &&
195	                            CONVERSATION_TRACKER_TYPES.has(rule.systemType)
196	                          }
197	                          title={
198	                            rule.systemType &&
199	                            CONVERSATION_TRACKER_TYPES.has(rule.systemType)
200	                              ? "Conversation tracker rules are managed automatically"
201	                              : undefined
202	                          }
203	                          onCheckedChange={async (enabled) => {
204	                            const isSystemRule = !!rule.systemType;
205	
206	                            // Optimistic update
207	                            mutate(
208	                              data?.map((r) =>
209	                                isSystemRule
210	                                  ? r.systemType === rule.systemType
211	                                    ? { ...r, enabled }
212	                                    : r
213	                                  : r.id === rule.id
214	                                    ? { ...r, enabled }
215	                                    : r,
216	                              ),
217	                              { revalidate: false },
218	                            );
219	
220	                            const result = await toggleRule({
221	                              ruleId: isSystemRule ? undefined : rule.id,
222	                              systemType: rule.systemType || undefined,
223	                              enabled,
224	                            });
225	
226	                            if (result?.serverError) {
227	                              toastError({
228	                                description: `There was an error ${
229	                                  enabled ? "enabling" : "disabling"
230	                                } your rule. ${result.serverError || ""}`,
231	                              });
232	                            }
233	
234	                            // Revalidate to sync with server
235	                            mutate();
236	                          }}
237	                        />
