261	                                aria-haspopup="true"
262	                                size="icon"
263	                                variant="ghost"
264	                                onClick={(e) => e.stopPropagation()}
265	                              >
266	                                <MoreHorizontalIcon className="size-4" />
267	                                <span className="sr-only">Toggle menu</span>
268	                              </Button>
269	                            </DropdownMenuTrigger>
270	                            <DropdownMenuContent
271	                              align="end"
272	                              onClick={(e) => e.stopPropagation()}
273	                            >
274	                              <DropdownMenuItem
275	                                onClick={() => {
276	                                  ruleDialog.onOpen({
277	                                    ruleId: rule.id,
278	                                    editMode: true,
279	                                  });
280	                                }}
281	                              >
282	                                <PenIcon className="mr-2 size-4" />
283	                                Edit manually
284	                              </DropdownMenuItem>
285	                              <DropdownMenuItem
286	                                onClick={() => {
287	                                  setInput(
288	                                    `I'd like to edit the "${rule.name}" rule:\n`,
289	                                  );
290	                                  setOpen((arr) => [...arr, "chat-sidebar"]);
291	                                }}
292	                              >
293	                                <SparklesIcon className="mr-2 size-4" />
294	                                Edit via AI
295	                              </DropdownMenuItem>
296	                              <DropdownMenuItem
297	                                onClick={() => {
298	                                  ruleDialog.onOpen({
299	                                    duplicateRule: rule,
300	                                  });
301	                                }}
302	                              >
303	                                <CopyIcon className="mr-2 size-4" />
304	                                Duplicate
305	                              </DropdownMenuItem>
306	                              <DropdownMenuItem asChild>
307	                                <Link
308	                                  href={prefixPath(
309	                                    emailAccountId,
310	                                    `/automation?tab=history&ruleId=${rule.id}`,
311	                                  )}
312	                                >
313	                                  <HistoryIcon className="mr-2 size-4" />
314	                                  History
315	                                </Link>
316	                              </DropdownMenuItem>
317	                              {!rule.systemType && (
318	                                <>
319	                                  <DropdownMenuSeparator />
320	
321	                                  <DropdownMenuItem
322	                                    onClick={async () => {
323	                                      const yes = confirm(
324	                                        `Are you sure you want to delete the rule "${rule.name}"?`,
325	                                      );
326	                                      if (yes) {
327	                                        toast.promise(
328	                                          async () => {
329	                                            const res = await deleteRuleAction(
330	                                              emailAccountId,
331	                                              { id: rule.id },
332	                                            );
333	
334	                                            if (
335	                                              res?.serverError ||
336	                                              res?.validationErrors
337	                                            ) {
338	                                              throw new Error(
339	                                                res?.serverError ||
340	                                                  "There was an error deleting your rule",
341	                                              );
342	                                            }
343	
344	                                            mutate(
345	                                              (currentRules) =>
346	                                                currentRules?.filter(
347	                                                  (currentRule) =>
348	                                                    currentRule.id !== rule.id,
349	                                                ),
350	                                              { revalidate: false },
351	                                            );
352	                                            mutate();
353	                                          },
354	                                          {
355	                                            loading: "Deleting rule...",
356	                                            success: "Rule deleted",
357	                                            error: (error) =>
358	                                              `Error deleting rule. ${error.message}`,
359	                                            finally: () => {
360	                                              mutate();
361	                                            },
362	                                          },
363	                                        );
364	                                      }
365	                                    }}
366	                                  >
367	                                    <Trash2Icon className="mr-2 size-4" />
368	                                    Delete
369	                                  </DropdownMenuItem>
370	                                </>
371	                              )}
372	                            </DropdownMenuContent>
373	                          </DropdownMenu>
374	                        )}
375	                      </TableCell>
376	                    </TableRow>
377	                  );
378	                })}
379	              </TableBody>
380	            </Table>
381	          ) : (
382	            <NoRules />
383	          )}
384	        </LoadingContent>
385	      </Card>
386	
387	      <RuleDialog
388	        ruleId={ruleDialog.data?.ruleId}
389	        duplicateRule={ruleDialog.data?.duplicateRule}
390	        isOpen={ruleDialog.isOpen}
391	        onClose={ruleDialog.onClose}
392	        onSuccess={() => {
393	          mutate();
394	          ruleDialog.onClose();
395	        }}
396	        editMode={ruleDialog.data?.editMode}
397	      />
398	    </div>
399	  );
