402	export function ActionBadges({
403	  actions,
404	  provider,
405	  labels,
406	}: {
407	  actions: {
408	    id: string;
409	    type: ActionType;
410	    label?: string | null;
411	    labelId?: string | null;
412	    folderName?: string | null;
413	    content?: string | null;
414	    to?: string | null;
415	  }[];
416	  provider: string;
