418	}) {
419	  const visibleActions = getVisibleActions(actions);
420	
421	  return (
422	    <div className="flex gap-1 sm:gap-2 flex-wrap min-w-0 justify-start">
423	      {visibleActions.map((action) => {
424	        const Icon = getActionIcon(action.type);
425	
426	        return (
427	          <Badge
428	            key={action.id}
429	            color={getActionColor(action.type)}
430	            className="w-fit sm:text-nowrap shrink-0"
431	          >
432	            <Icon className="size-3 mr-1.5 hidden sm:block" />
433	            {getActionDisplay(action, provider, labels)}
434	          </Badge>
435	        );
436	      })}
437	    </div>
438	  );
439	}
440	
441	function getVisibleActions<T extends { type: ActionType }>(actions: T[]): T[] {
442	  const sortedActions = sortActionsByPriority(actions);
443	  const hasEmailDraft = sortedActions.some(
444	    (action) => action.type === "DRAFT_EMAIL",
445	  );
446	
447	  return sortedActions.filter(
448	    (action) => !(action.type === "DRAFT_MESSAGING_CHANNEL" && hasEmailDraft),
449	  );
450	}
