772	async function autoJoinOrganization(emailAccountId: string) {
773	  const orgs = await prisma.organization.findMany({
774	    select: { id: true },
775	    take: 2,
776	  });
777	
778	  if (orgs.length !== 1) {
779	    if (orgs.length === 0) {
780	      logger.warn("[autoJoinOrganization] No organization found to auto-join");
781	    } else {
782	      logger.warn(
783	        "[autoJoinOrganization] Multiple organizations found, skipping auto-join",
784	      );
785	    }
786	    return;
787	  }
788	
789	  const organizationId = orgs[0].id;
790	
791	  const member = await prisma.member.upsert({
792	    where: { emailAccountId },
793	    update: {},
794	    create: {
795	      organizationId,
796	      emailAccountId,
797	      role: "member",
798	      allowOrgAdminAnalytics: env.AUTO_ENABLE_ORG_ANALYTICS,
799	    },
800	    select: { id: true, createdAt: true },
801	  });
802	
803	  logger.info("[autoJoinOrganization] Auto-joined user to organization", {
804	    emailAccountId,
805	    organizationId,
806	    memberId: member.id,
807	  });
808	}
